{
    try
    {
        // 1. Get the GraphicalLayer (replace with your layer name)
        GraphicalLayer layer = project.GraphicalLayers.GetGraphicalLayerByName("Cables - Power");

        if (layer != null)
        {
            // 2. Set the Layer property
            connection.Layer = layer;
            Console.WriteLine("Layer assigned successfully.");
        }
        else
        {
            Console.WriteLine("Layer not found.");
        }
    }
    catch (ArgumentException ex)
    {
        Console.WriteLine($"Error assigning layer: {ex.Message}. Ensure the layer is a 3D layer.");
    }
    catch (BaseException ex)
    {
        Console.WriteLine($"Error assigning layer: {ex.Message}");
    }
}
else
{
    Console.WriteLine("Connection3D or Project object is null.");
}
```

