        objectIds.Add(objectIdWithoutProjectId);
    }

    // 4. Create an Edit object
    Edit edit = new Edit();

    // 5. Select the objects (deselecting any existing selection)
    edit.SelectObjects(project.ProjectLinkFilePath, objectIds, true);
