using System;

// Assuming you have a valid MDPartsDatabase object called 'partsDatabase'
// and a valid MDPartsManagement object called 'partsManagement'

MDPartsDatabaseMessages partsDatabaseMessages = new MDPartsDatabaseMessages(partsDatabase);
partsDatabaseMessages.ShowImmediately = true; // Make sure the message is displayed immediately
partsDatabaseMessages.ReuseMessages = false; // Ensure a new message is always added

try
{
    // Example usage
    MDPartsMessage newMessage = partsDatabaseMessages.AddMessage(
        1234, // Error number
        "Parameter1|Parameter2", // Parameters (if any)
        "YourPartNumber", // Part number
