            Console.WriteLine($"Project Name: {propertyValue.Value}");
        }
        catch (PropertyNotFoundException ex)
        {
            // Handle specific exceptions
            Console.WriteLine($"Error: Property not found: {ex.Message}");
        }
        catch (ArgumentNullException ex)
        {
            Console.WriteLine($"Error: Null argument: {ex.Message}");
        }
        catch (Exception ex)
        {
            // Handle general exceptions
            Console.WriteLine($"An unexpected error occurred: {ex.Message}");
            // Log the exception details (e.g., to a file)
            // Optionally, re-throw the exception if you can't handle it locally
            // throw;
        }
        finally
        {
            // Code that always executes (e.g., cleanup)
            Console.WriteLine("Finished processing.");
        }
    }
    ```

2.  **Handle Specific Exceptions:**  Catch specific exception types (e.g., `PropertyNotFoundException`, `ArgumentNullException`, `InvalidOperationException`) to provide more targeted error handling. This allows you to respond appropriately to different error scenarios.

3.  **Log Errors:**  Use a logging mechanism (e.g., `Console.WriteLine`, a file logger, or a dedicated logging library) to record error messages, exception details, and timestamps. This is crucial for debugging and troubleshooting scripts.

