/// <param name="x">The X coordinate (mm) for the terminal placement.</param>
/// <param name="y">The Y coordinate (mm) for the terminal placement.</param>
/// <returns>True if the terminal was created successfully; otherwise, false.</returns>
public bool CreateTerminal(Project project, string pageName, string deviceName, string articleNumber, double x, double y)
{
    try
    {
        // 1. Get the page
        Page page = project.Pages.GetPage(pageName);
        if (page == null)
        {
            Log.Error($"Page not found: {pageName}");
            return false;
        }

        // 2. Create the terminal function
        Function terminalFunction = new Function();
        terminalFunction.FunctionCategory = FunctionCategory.Terminal;
        terminalFunction.Name = deviceName;

        // 3. Create the symbol reference
        SymbolReference symbolReference = new SymbolReference();
        symbolReference.SymbolLibrary = "EPLAN1"; // Replace with your symbol library
        symbolReference.SymbolName = "T_0001"; // Replace with your symbol name
        symbolReference.Location = new PointD(x, y);

        // 4. Place the terminal on the page
        symbolReference.Create(page, terminalFunction);

        // 5. Assign the article
        string variantNumber = "1"; // Replace with your variant number
        uint count = 1; // Replace with your count
        ArticleReference articleReference = project.AddArticleReference(articleNumber, variantNumber, count);
        // Example: Property ID for Article (check EPLAN API documentation)
        int propertyId = 20000; // Replace with the actual property ID
        terminalFunction.Properties.SetValue(propertyId, articleNumber);

        return true;
    }
    catch (Exception ex)
    {
        Log.Error($"Error creating terminal: {ex.Message}");
        return false;
    }
}
