Page oPage = oProject.Pages[0]; // Replace with your page

try {
    // 1. Prepare the symbol
    SymbolLibrary oSymbolLibrary = new SymbolLibrary(oProject, "SPECIAL"); // Replace with your library name
    Symbol oSymbol = new Symbol(oSymbolLibrary, "SH"); // Replace with your symbol name

    // 2. Create the Shield
    Shield oShield = new Shield();
    oShield.Create(oPage, oSymbol, new PointD(50.0, 200.0), new PointD(120.0, 230.0));

    // 3. (Optional) Set properties if needed, e.g., the logical area
