                // Define the function definition (Area definition)
                FunctionDefinition functionDefinition = null;
                foreach (FunctionDefinition def in project.FunctionDefinitions)
                {
                    if (def.Category == FunctionCategory.AreaDefinition)
                    {
                        functionDefinition = def;
                        break;
                    }
                }

                if (functionDefinition == null)
                {
                    MessageBox.Show("No Area Definition Function Definition found in the project.", "Error", MessageBoxButtons.OK, MessageBoxIcon.Error);
                    return;
                }

                // Create the transient area
                Area transientArea = Area.CreateTransient(project, functionDefinition, areaSize);

                if (transientArea != null)
                {
                    // Get the size of the area
                    PointD retrievedSize = transientArea.Size;

