    {
        try
        {
            // 1. Initialize EPLAN application
            using (var app = new Eplan.EplApi.System.EplApplication())
            {
                app.Init(""); // Initialize EPLAN

                // 2. Get the project
                Project project = new Project(projectPath);

                // 3. Get the page
                Page page = project.Pages.Find(pageName);

                if (page == null)
                {
                    throw new ArgumentException($"Page '{pageName}' not found in project.");
