public class CreatePlugStrip
{
    [EplAction(Name = "Create Plug Strip", Description = "Creates a new PlugStrip object.")]
    public void CreateAndPlacePlugStrip()
    {
        try
        {
            // Get the active project
            Project project = new Project(Project.ActiveProject); // Use ActiveProject to get the currently open project

            // Check if a project is open
            if (project == null || string.IsNullOrEmpty(project.Name))
            {
                MessageDlg.Show("No project is currently open.", "Error", MessageBoxButtons.Ok, MessageBoxIcon.Error);
                return;
            }

            // Define the page where the PlugStrip will be placed.  Replace with your desired page name and type.
            string pageName = "=A1-1"; // Example page name
            PageType pageType = PageType.Schematic; // Example page type

            // Find the page
            Page page = null;
            foreach (Page p in project.Pages)
            {
                if (p.Name == pageName && p.PageType == pageType)
                {
                    page = p;
                    break;
                }
            }

            // If the page is not found, create a new page
            if (page == null)
            {
                page = new Page(project);
                page.Name = pageName;
                page.PageType = pageType;
                // You might want to set other page properties here, like page size.
            }

            // Create a new PlugStrip object
            PlugStrip plugStrip = new PlugStrip();

            // Set the project for the PlugStrip
            plugStrip.Project = project;

            // Set the page for the PlugStrip
            plugStrip.Page = page;

            // Set the location of the PlugStrip (in millimeters)
            Location location = new Location(10, 10, 0);

            // Create the PlugStrip on the page
            plugStrip.Create(page, location);

            // Optionally, set some properties of the PlugStrip
            // Example: Set the device tag
            // plugStrip.Properties.FUNC_DEVICETAG_FULL.Set(new PropertyValue("X1"));

            // Refresh the project to reflect the changes
            project.Update();

            MessageDlg.Show("PlugStrip created and placed successfully.", "Success", MessageBoxButtons.Ok, MessageBoxIcon.Information);
        }
        catch (LockingException ex)
        {
            MessageDlg.Show("Error: Could not lock the project.  " + ex.Message, "Error", MessageBoxButtons.Ok, MessageBoxIcon.Error);
        }
        catch (BaseException ex)
        {
            MessageDlg.Show("An unexpected error occurred: " + ex.Message, "Error", MessageBoxButtons.Ok, MessageBoxIcon.Error);
        }
        catch (Exception ex)
        {
            MessageDlg.Show("An unexpected error occurred: " + ex.Message, "Error", MessageBoxButtons.Ok, MessageBoxIcon.Error);
        }
    }
}
