{
    [Start]
    public static void Run()
    {
        try
        {
            // Assuming you have a valid SegmentTemplate object
            // Replace with your actual SegmentTemplate object
            // For example, you might get it from a project or a specific part
            // SegmentTemplate mySegmentTemplate = ...;

            // Example: Get the first SegmentTemplate in the project (replace with your logic)
