            if (project == null)
            {
                Console.WriteLine("No project is open.");
                return;
            }

            DMObjectsFinder finder = new DMObjectsFinder(project);
            SegmentTemplatesFilter filter = new SegmentTemplatesFilter();
            StorableObject[] segmentTemplates = finder.GetStorableObjects(filter);

            if (segmentTemplates.Length == 0)
            {
                Console.WriteLine("No segment templates found.");
                return;
            }

            SegmentTemplate mySegmentTemplate = (SegmentTemplate)segmentTemplates[0];

            // Define the index for the part number
            int index = 2;

            // Access the SegmentTemplatePropertyList
            SegmentTemplatePropertyList propertyList = mySegmentTemplate.Properties;

            // Get the PropertyValue for FUNC_ARTICLE_PARTNR at the specified index
            PropertyValue partNumberPropertyValue = propertyList.Property(SegmentTemplatePropertyList.Properties.FUNC_ARTICLE_PARTNR, index);

            // Check if the PropertyValue is not null and has a value
            if (partNumberPropertyValue != null && !string.IsNullOrEmpty(partNumberPropertyValue.ToString()))
            {
                // Get the part number as a string
                string partNumber = partNumberPropertyValue.ToString();

                // Output the part number
                Console.WriteLine($"Part Number at index {index}: {partNumber}");
            }
            else
            {
                Console.WriteLine($"Part Number at index {index} not found or has no value.");
            }
        }
        catch (Exception ex)
        {
            // Handle any exceptions that occur
            Console.WriteLine($"An error occurred: {ex.Message}");
