using System;
using Eplan.EplApi.Base;
using Eplan.EplApi.DataModel;

public class ChangePlugCategory
{
    [Start]
    public void Run()
    {
        try
        {
            // 1. Get the current project
            Project project = new ProjectManager().CurrentProject;

            // 2. Check if a project is open
            if (project == null)
            {
                throw new BaseException("No project is currently open.", MessageLevel.Error);
            }

            // 3. Assuming there is a plug object in the project, get the first one
            // You might need to adjust the filtering logic based on your project's structure
            // This is just a placeholder to get a plug object
            Function[] plugs = project.Pages.SelectMany(page => page.Functions.OfType<Function>())
                                     .Where(f => f.Category == Function.Enums.Category.Plug)
                                     .ToArray();

            if (plugs.Length == 0)
            {
                throw new BaseException("No Plug objects found in the project.", MessageLevel.Error);
            }

            Function plug = plugs[0];

            // 4. Attempt to change the category to TERMINAL
            try
            {
                plug.Category = Function.Enums.Category.Terminal; // This should throw WrongCategoryException
            }
            catch (WrongCategoryException)
            {
                // Expected exception: Category change is not allowed for Plug to Terminal
                Console.WriteLine("Successfully caught WrongCategoryException.");
                return; // Exit the script after catching the exception
            }

            // 5. If we reach here, the exception was not thrown, which is an error.
            throw new BaseException("WrongCategoryException was not thrown as expected.", MessageLevel.Error);
        }
        catch (BaseException ex)
        {
            // Handle any EPLAN API exceptions
            Console.WriteLine($"EPLAN API Error: {ex.Message}");
        }
        catch (Exception ex)
        {
            // Handle any other exceptions
            Console.WriteLine($"General Error: {ex.Message}");
        }
    }
}
